VALUES
  ('dietitian-moex-11304', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列關於鈣補充劑之使用的敘述，何者錯誤？ Ca/P比值太低會促使PTH分泌，增加骨質流失 鈣補充量太多可能降低Fe，Mg，Zn等礦物質之吸收 老年人補充鈣應與餐點分開食用，以增加鈣的吸收 calcium citrate之吸收率較calcium carbonate佳', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11305', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列關於停經後婦女之骨質變化的敘述，何者錯誤？ 骨小樑（trabecular bone）流失的速率較骨皮質（cortical bone）來的快 停經後隨著停經年數的增加骨質流失的速率也逐年增加 停經後骨質流失的情形較同齡男性嚴重 停經婦女補充雌激素（estrogen）可使骨質流失的情形趨緩', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11306', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '癌症病人因治療或癌症本身而致嗅覺味覺改變時，下列敘述何者正確？ 對苦味敏感度降低    對酸甜敏感度增加 避免供應冷盤或甜點    通常對肉類的接受度較差', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "85ba92118f33", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11307', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '元素飲食（Elemental diet）比聚合配方飲食（Polymeric formulas）之滲透壓： 較高  較低  相同  視產品而定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "8c35cacfa49d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
