  ('dietitian-moex-11309', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關胃部手術後可能發生傾食症候群（Dumping syndrome）之症狀或處理方式，何者正確？ 容易產生進食後高血糖的情況  進食時採半坐臥姿勢，以減緩胃排空速度 適合低蛋白、低醣、適量脂肪的飲食方式  應避免酒精飲料，但甜食或甜飲料無妨', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "8c35cacfa49d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
